import (
	"container/heap"
	"math"
)

// Item represents a node in the priority queue for Dijkstra's algorithm.
type Item struct {
	node     int
	distance int64
}

// PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want the minimum distance item to have the highest priority.
	return pq[i].distance < pq[j].distance
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// dijkstra runs Dijkstra's algorithm from a starting node.
// adj is the adjacency list: adj[u] = []Edge{...}
// Edge contains {to, weight}.
func dijkstra(n int, adj [][]struct{ to int; weight int64 }, startNode int) []int64 {
	const INF = math.MaxInt64
	dist := make([]int64, n)
	for i := range dist {
		dist[i] = INF
	}
	dist[startNode] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Item{node: startNode, distance: 0})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		u := item.node
		d := item.distance

		if d > dist[u] {
			continue
		}

		for _, edge := range adj[u] {
			v := edge.to
			weight := edge.weight

			if dist[u]+weight < dist[v] {
				dist[v] = dist[u] + weight
				heap.Push(&pq, &Item{node: v, distance: dist[v]})
			}
		}
	}
	return dist
}

func solve(n int64, prices []int64, roads [][]int64) []int64 {
	N := int(n)

	// 1. Build Graphs
	// adjEmpty: Edge weight = cost_i (Empty state)
	adjEmpty := make([][]struct{ to int; weight int64 }, N)
	// adjCarry: Edge weight = cost_i * tax_i (Carry state)
	adjCarry := make([][]struct{ to int; weight int64 }, N)

	for _, road := range roads {
		u := int(road[0])
		v := int(road[1])
		cost := road[2]
		tax := road[3]

		// Empty State Edges (undirected)
		adjEmpty[u] = append(adjEmpty[u], struct{ to int; weight int64 }{to: v, weight: cost})
		adjEmpty[v] = append(adjEmpty[v], struct{ to int; weight int64 }{to: u, weight: cost})

		// Carry State Edges (undirected)
		carryWeight := cost * tax
		adjCarry[u] = append(adjCarry[u], struct{ to int; weight int64 }{to: v, weight: carryWeight})
		adjCarry[v] = append(adjCarry[v], struct{ to int; weight int64 }{to: u, weight: carryWeight})
	}

	// 2. Calculate All-Pairs Shortest Paths (APSP)

	// DistE[i][j] = Min cost i -> j (Empty)
	DistE := make([][]int64, N)
	for i := 0; i < N; i++ {
		DistE[i] = dijkstra(N, adjEmpty, i)
	}

	// DistC[j][i] = Min cost j -> i (Carry)
	// Since the graphs are undirected, we calculate DistC[i][j] = Min cost i -> j (Carry)
	DistC := make([][]int64, N)
	for j := 0; j < N; j++ {
		DistC[j] = dijkstra(N, adjCarry, j)
	}

	// 3. Determine Minimum Cost for each shop i
	ans := make([]int64, N)
	const INF = math.MaxInt64

	for i := 0; i < N; i++ {
		// Initial minimum cost: Buy locally at i
		minCost := prices[i]

		// Check all possible buying shops j
		for j := 0; j < N; j++ {
			if i == j {
				continue
			}

			// Cost calculation:
			// 1. i -> j empty: DistE[i][j]
			// 2. Buy at j: prices[j]
			// 3. j -> i carrying: DistC[j][i]

			// Note: Since the road network is undirected and costs are symmetric for both states,
			// DistC[j][i] = DistC[i][j]. We use DistC[j][i] to be explicit about the required path direction (return to i).

			dist_i_to_j_empty := DistE[i][j]
			dist_j_to_i_carry := DistC[j][i]

			if dist_i_to_j_empty == INF || dist_j_to_i_carry == INF {
				// Cannot reach or return
				continue
			}

			currentCost := dist_i_to_j_empty + prices[j] + dist_j_to_i_carry

			if currentCost < minCost {
				minCost = currentCost
			}
		}
		ans[i] = minCost
	}

	return ans
}
