// dijkstra runs Dijkstra's algorithm from a source node on the given graph.
// It returns an array of shortest distances from the source to all other nodes.
func dijkstra(n int, graph Graph, start int) []int64 {
	distances := make([]int64, n)
	for i := range distances {
		distances[i] = math.MaxInt64
	}
	distances[start] = 0

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{node: start, distance: 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Item)
		u := current.node
		distU := current.distance

		if distU > distances[u] {
			continue
		}

