			v := edge.to
			weight := edge.weight
			newDist := distU + weight

			if newDist < distances[v] {
				distances[v] = newDist
				heap.Push(&pq, &Item{node: v, distance: newDist})
			}
		}
	}
	return distances
}

// solve calculates the minimum cost for each store.
func solve(n int64, prices []int64, roads [][]int64) []int64 {
	N := int(n)

	// 1. Build Graphs G_E (Empty) and G_C (Carrying)
	graphE := make(Graph, N)
	graphC := make(Graph, N)

	for _, road := range roads {
		u := int(road[0])
		v := int(road[1])
		cost := road[2]
		tax := road[3]

		// Empty travel cost
		weightE := cost
		graphE[u] = append(graphE[u], Edge{to: v, weight: weightE})
		graphE[v] = append(graphE[v], Edge{to: u, weight: weightE})

		// Carrying travel cost
		weightC := cost * tax
		graphC[u] = append(graphC[u], Edge{to: v, weight: weightC})
		graphC[v] = append(graphC[v], Edge{to: u, weight: weightC})
	}

	// 2. Compute APSP for G_E and G_C
	// DE[i][j] = D_E(i, j)
	DE := make([][]int64, N)
	// DC[i][j] = D_C(i, j)
	DC := make([][]int64, N)

	for i := 0; i < N; i++ {
		DE[i] = dijkstra(N, graphE, i)
		DC[i] = dijkstra(N, graphC, i)
	}

	// 3. Calculate the final answer array
	ans := make([]int64, N)

	for i := 0; i < N; i++ {
		// Option 1: Direct purchase
		minCost := prices[i]

		// Option 2: Indirect purchase via store j
		for j := 0; j < N; j++ {
			// If j == i, the indirect path is just buying locally, which is already covered by direct purchase.
			if i == j {
				continue
			}

			// Check reachability. If either path is infinite, skip this j.
			dE_ij := DE[i][j]
			dC_ij := DC[i][j]

			if dE_ij == math.MaxInt64 || dC_ij == math.MaxInt64 {
				continue
			}

			// Cost = D_E(i, j) + prices[j] + D_C(j, i)
			// Since paths are symmetric, D_C(j, i) = D_C(i, j)
			cost := dE_ij + prices[j] + dC_ij

			if cost < minCost {
				minCost = cost
			}
		}
		ans[i] = minCost
	}

	return ans
}
