	adjEmpty := make([][]Edge, N)
	adjCarry := make([][]Edge, N)

	for _, road := range roads {
		u := int(road[0])
		v := int(road[1])
		cost := road[2]
		tax := road[3]

		// Empty Travel Cost
		// u <-> v cost
		adjEmpty[u] = append(adjEmpty[u], Edge{v, cost})
		adjEmpty[v] = append(adjEmpty[v], Edge{u, cost})

		// Carrying Travel Cost
		// u <-> v cost * tax
