		minCost := prices[i]

		// Option 2: Travel to j, buy, return to i
		for j := 0; j < N; j++ { // j is the purchase shop
			if i == j {
				// Already covered by Option 1, but safe to check the path calculation too
				// Cost = D_empty[i][i] + prices[i] + D_carry[i][i] = 0 + prices[i] + 0
				continue 
